### Step 1: Replace shellIndexForStep
```go
func (m *addWizardModel) shellIndexForStep(s addStep) int {
    // Permutation table:
    // +Type +Triage: Source(0) Type(1) Discovery(2) Triage(3) Review(4) Execute(5)
    // +Type -Triage: Source(0) Type(1) Discovery(2) Review(3) Execute(4)
    // -Type +Triage: Source(0) Discovery(1) Triage(2) Review(3) Execute(4)
    // -Type -Triage: Source(0) Discovery(1) Review(2) Execute(3)
    hasType := m.preFilterType == ""
    has := m.hasTriageStep

    switch s {
    case addStepSource:
        return 0
    case addStepType:
        if !hasType {
            panic("shellIndexForStep: addStepType in -Type permutation")
        }
        return 1
    case addStepDiscovery:
        if hasType { return 2 }
        return 1
    case addStepTriage:
        if !has {
            panic("shellIndexForStep: addStepTriage in -Triage permutation")
        }
        if hasType { return 3 }
        return 2
    case addStepReview:
        if hasType && has { return 4 }
        if hasType || has { return 3 }
        return 2
    case addStepExecute:
        if hasType && has { return 5 }
        if hasType || has { return 4 }
        return 3
    }
    return int(s)
}
```

### Step 2: Add stepForShellIndex
```go
func (m *addWizardModel) stepForShellIndex(idx int) addStep {
    hasType := m.preFilterType == ""
    hasTriage := m.hasTriageStep

    switch {
    case hasType && hasTriage:
        return addStep(idx)
    case hasType && !hasTriage:
        switch idx {
        case 0: return addStepSource
        case 1: return addStepType
        case 2: return addStepDiscovery
        case 3: return addStepReview
        case 4: return addStepExecute
        }
    case !hasType && hasTriage:
        switch idx {
        case 0: return addStepSource
        case 1: return addStepDiscovery
        case 2: return addStepTriage
        case 3: return addStepReview
        case 4: return addStepExecute
        }
    default:
        switch idx {
        case 0: return addStepSource
        case 1: return addStepDiscovery
        case 2: return addStepReview
        case 3: return addStepExecute
        }
    }
    return addStepSource
}
```

